CREATE TABLE camps (id UUID PRIMARY KEY, name VARCHAR(150) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, description TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE rooms (id UUID PRIMARY KEY, camp_id UUID NOT NULL REFERENCES camps(id) ON DELETE CASCADE, name VARCHAR(120) NOT NULL, capacity INTEGER NOT NULL CHECK(capacity > 0), gender VARCHAR(20) NOT NULL, UNIQUE(camp_id,name));
CREATE TABLE discussion_groups (id UUID PRIMARY KEY, camp_id UUID NOT NULL REFERENCES camps(id) ON DELETE CASCADE, name VARCHAR(120) NOT NULL, capacity INTEGER, gender_separated BOOLEAN NOT NULL DEFAULT FALSE, UNIQUE(camp_id,name));
CREATE TABLE campers (id UUID PRIMARY KEY, camp_id UUID NOT NULL REFERENCES camps(id) ON DELETE CASCADE, name VARCHAR(180) NOT NULL, normalized_name VARCHAR(180) NOT NULL, gender VARCHAR(20) NOT NULL, birthdate DATE NOT NULL, room_id UUID REFERENCES rooms(id) ON DELETE SET NULL, discussion_group_id UUID REFERENCES discussion_groups(id) ON DELETE SET NULL, version BIGINT NOT NULL DEFAULT 0);
CREATE INDEX idx_camper_camp ON campers(camp_id); CREATE INDEX idx_camper_name ON campers(camp_id, normalized_name);
CREATE TABLE preferences (id UUID PRIMARY KEY, camper_id UUID NOT NULL REFERENCES campers(id) ON DELETE CASCADE, raw_name VARCHAR(180) NOT NULL, matched_camper_id UUID REFERENCES campers(id) ON DELETE SET NULL, status VARCHAR(20) NOT NULL, similarity DOUBLE PRECISION, alternatives TEXT);
